var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"숲 속의 오두막집에 늙은 나무꾼이 살았습니다.","JPN":"むかしむかし、森の中の小屋に木こりのおじいさんが\\n暮らしていました。","ENG":"There was an old woodcutter who lived in a cabin in the middle of a forest.","TWN":"從前，在深林中小木屋裡住著一個老樵夫。"},"stage":{"bg":"EV_SIGMA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"나무꾼은 손재주가 좋아 팔고 남은 나무를 깎아 인형을 만들어 내다팔곤 했어요.","JPN":"木こりは手先が器用だったので、余った木で\\n木彫り人形をつくり、売っていました。","ENG":"He was good with his hands. He carved dolls out of leftover wood and sold them at the market.","TWN":"樵夫手藝很好，他會把沒賣出去的木頭雕成人偶並拿出去賣。"},"stage":{"bg":"EV_SIGMA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"여느 때처럼 초를 켜고 나무를 깎던 나무꾼은 그날 아주 아름다운 인형을 만들었습니다.","JPN":"ある日、いつもどおりロウソクを灯して作業をしていた\\n木こりは、とても綺麗な人形を完成させました。","ENG":"Every night he'd carve wood by candlelight, and one day he created a very beautiful doll.","TWN":"有一天，樵夫把木頭雕成了一個非常美麗的人偶。"},"stage":{"bg":"EV_SIGMA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"보다 완벽한 인형은 앞으로 없을 거라 생각한 나무꾼은 그 인형을 파는 대신 간직하기로 했죠.","JPN":"これ以上の人形はつくれないだろうと思った木こりは、\\nその人形は売らずに自分のものにしようと思いました。","ENG":"He thought he could never make anything better than this, so he decided to keep it to himself.","TWN":"樵夫對自己的作品非常滿意，於是他沒有賣掉那個人偶，而是自己留著。"},"stage":{"bg":"EV_SIGMA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"나무꾼의 인형에 대한 애착은 날이 갈수록 커져 인형이 사람이 되길 바랬습니다.","JPN":"人形に対する木こりの愛情は日増しにふくらんでいき、\\nやがてその人形が人間になることを願うようになりました。","ENG":"The woodcutter became obsessed with his doll, to the point that he wanted it to come to life.","TWN":"樵夫越來越喜愛人偶，他甚至希望人偶能變成真正的人。"},"stage":{"bg":"EV_SIGMA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 그는 산꼭대기의 요정을 찾아가 인형에게 자신의 생명을 나눠달라고 소원을 빌었어요.","JPN":"そして彼は山頂に住む妖精を訪ね、人形に\\n自分の命を分け与えるようにお願いをしました。","ENG":"He went to a fairy who lived on the top of the mountain, and pleaded with it to give some of his life to his doll.","TWN":"於是他去找了住在山頂的妖精，請求把自己的生命分給人偶。"},"stage":{"bg":"EV_SIGMA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"요정은 그 부탁을 들어주게 되면, 나무꾼은 5년 밖에 살지 못할 것이라고 했습니다.","JPN":"妖精は、その願いを叶えてしまうと木こりはこの先5年しか生きられないと告げました。","ENG":"The fairy said he could only live five more years if he shared his life with his doll.","TWN":"妖精說，如果自己接受這個請求，樵夫就會只剩下5年的壽命。"},"stage":{"bg":"EV_SIGMA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼에도 나무꾼은 흔쾌히 수락했습니다.","JPN":"しかし、木こりは喜んで受け入れました。","ENG":"The woodcutter happily said yes.","TWN":"但樵夫依舊非常欣喜地同意了。"},"stage":{"bg":"EV_SIGMA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"소원을 빈 나무꾼이 집으로 돌아오자, 인형은 정말로 소녀가 되어 있었습니다.","JPN":"木こりが小屋に帰ると、人形は少女になっていました。","ENG":"When he came back to his cabin, his doll had become a girl.","TWN":"回到家後，樵夫發現人偶果真變成了少女。"},"stage":{"bg":"EV_SIGMA_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"소녀는 인형일 적보다 훨씬 아름답고 사랑스러웠습니다.","JPN":"少女は人形だった頃よりも、美しく愛らしい姿でした。","ENG":"She was more beautiful and adorable than she was as a doll.","TWN":"少女比人偶更加美麗可人。"},"stage":{"bg":"EV_SIGMA_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"나무꾼은 소녀를 자신의 딸처럼 여기며 성심껏 가르치고 보살폈습니다.","JPN":"木こりは少女を我が子のように可愛がり、面倒をみました。","ENG":"The woodcutter raised her as his own daughter, teaching and caring for her with utmost dedication.","TWN":"樵夫把少女當成自己的女兒，盡心盡力地照顧她教導她。"},"stage":{"bg":"EV_SIGMA_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"인형일 적부터 느껴온 애정이 소녀에겐 익숙했습니다.","JPN":"人形だった頃から感じていた愛情は、少女にとって\\n馴染み深いものでした。","ENG":"She was used to his affection that she'd felt since she was a doll.","TWN":"少女知道樵夫從人偶時期開始就對自己百般呵護。"},"stage":{"bg":"EV_SIGMA_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 자신을 만들어준 나무꾼을 아빠라고 부르며 따랐습니다.","JPN":"自分をつくってくれた木こりのことをパパと呼び、\\n自然と慕うようになりました。","ENG":"She called him Daddy and loved him as if he really was her father.","TWN":"於是她也把樵夫當作父親。"},"stage":{"bg":"EV_SIGMA_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게 두 사람은 가족이 되었습니다.","JPN":"そうして、二人は家族になりました。","ENG":"Like that, they became family.","TWN":"兩個人就這樣成了一家人。"},"stage":{"bg":"EV_SIGMA_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"난 이 대목이 좋아.","JPN":"ボクはこのくだりが好きなんだ。","ENG":"I like this part,","TWN":"我喜歡這部分。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA_CB","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"피로 전혀 이어지지 않은 두 사람이 가족이 되는 것 말이야.","JPN":"血がつながってない二人が家族になるくだりね。","ENG":"where two strangers come together as family.","TWN":"兩個沒有任何血緣關係的人成為一家人了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA_CB","slots":{"L":null,"C":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CLEANER_NPC_NONAME_NULL","text":{"KOREA":"부모님이 뭔지 알아?","JPN":"「親」の意味がわかる？","ENG":"Do you know what parents are?","TWN":"你知道什麼叫父母嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA_CB","slots":{"L":null,"C":null,"R":{"char_id":"CLEANER_NPC_NONAME_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};